300→        u.put(91, new AccountSettingsUpgraderTo91());
301→
302→        UPGRADERS = Collections.unmodifiableMap(u);
303→    }
304→
305→    static Map<String, Object> validate(int version, Map<String, String> importedSettings, boolean useDefaultValues) {
