 9→/**
10→ * Replace folder entries of "-NONE-" with {@code null}.
11→ */
12→public class AccountSettingsUpgraderTo53 implements SettingsUpgrader {
13→    public static final String FOLDER_NONE = "-NONE-";
14→
15→    @Override
16→    public void upgrade(Map<String, Object> settings) {
17→        upgradeFolderEntry(settings, "archiveFolderName");
18→        upgradeFolderEntry(settings, "autoExpandFolderName");
19→        upgradeFolderEntry(settings, "draftsFolderName");
