 11→import com.fsck.k9.FontSizes;
 12→import com.fsck.k9.K9;
 13→import timber.log.Timber;
 14→
 15→/*
 16→ * TODO:
 17→ * - use the default values defined in GlobalSettings and AccountSettings when creating new
 18→ *   accounts
 19→ * - think of a better way to validate enums than to use the resource arrays (i.e. get rid of
 20→ *   ResourceArrayValidator); maybe even use the settings description for the settings UI
 21→ * - add unit test that validates the default values are actually valid according to the validator
 22→ */
 23→
 24→class Settings {
 25→    /**
 26→     * Version number of global and account settings.
 27→     *
 28→     * <p>
 29→     * This value is used as "version" attribute in the export file. It needs to be incremented
 30→     * when a global or account setting is added or removed, or when the format of a setting
 31→     * is changed (e.g. add a value to an enum).
 32→     * </p>
 33→     *
 34→     * @see SettingsExporter
 35→     */
 36→    public static final int VERSION = 100;
 37→
 38→    static Map<String, Object> validate(int version, Map<String, TreeMap<Integer, SettingsDescription<?>>> settings,
 39→            Map<String, String> importedSettings, boolean useDefaultValues) {
 40→
 41→        Map<String, Object> validatedSettings = new HashMap<>();
 42→        for (Map.Entry<String, TreeMap<Integer, SettingsDescription<?>>> versionedSetting : settings.entrySet()) {
 43→
 44→            // Get the setting description with the highest version lower than or equal to the
 45→            // supplied content version.
 46→            TreeMap<Integer, SettingsDescription<?>> versions = versionedSetting.getValue();
 47→            SortedMap<Integer, SettingsDescription<?>> headMap = versions.headMap(version + 1);
 48→
 49→            // Skip this setting if it was introduced after 'version'
 50→            if (headMap.isEmpty()) {
 51→                continue;
 52→            }
 53→
 54→            Integer settingVersion = headMap.lastKey();
 55→            SettingsDescription<?> desc = versions.get(settingVersion);
 56→
 57→            // Skip this setting if it is no longer used in 'version'
 58→            if (desc == null) {
 59→                continue;
 60→            }
 61→
 62→            String key = versionedSetting.getKey();
 63→
 64→            boolean useDefaultValue;
 65→            if (!importedSettings.containsKey(key)) {
 66→                Timber.v("Key \"%s\" wasn't found in the imported file.%s",
 67→                        key,
 68→                        (useDefaultValues) ? " Using default value." : "");
 69→
 70→                useDefaultValue = useDefaultValues;
 71→            } else {
 72→                String prettyValue = importedSettings.get(key);
 73→                try {
 74→                    Object internalValue = desc.fromPrettyString(prettyValue);
 75→                    validatedSettings.put(key, internalValue);
 76→                    useDefaultValue = false;
 77→                } catch (InvalidSettingValueException e) {
 78→                    Timber.v("Key \"%s\" has invalid value \"%s\" in imported file. %s",
 79→                            key,
 80→                            prettyValue,
 81→                            (useDefaultValues) ? "Using default value." : "Skipping.");
 82→
 83→                    useDefaultValue = useDefaultValues;
 84→                }
 85→            }
 86→
 87→            if (useDefaultValue) {
 88→                Object defaultValue = desc.getDefaultValue();
 89→                validatedSettings.put(key, defaultValue);
 90→            }
 91→        }
 92→
 93→        return validatedSettings;
 94→    }
 95→
 96→    /**
 97→     * Convert settings from the internal representation to the string representation used in the
 98→     * preference storage.
 99→     *
100→     * @param settings
101→     *         The map of settings to convert.
102→     * @param settingDescriptions
103→     *         The structure containing the {@link SettingsDescription} objects that will be used
104→     *         to convert the setting values.
105→     *
106→     * @return The settings converted to the string representation used in the preference storage.
107→     */
108→    public static Map<String, String> convert(Map<String, Object> settings,
109→            Map<String, TreeMap<Integer, SettingsDescription<?>>> settingDescriptions) {
110→        Map<String, String> serializedSettings = new HashMap<>();
111→
112→        for (Entry<String, Object> setting : settings.entrySet()) {
113→            String settingName = setting.getKey();
114→            Object internalValue = setting.getValue();
115→
116→            TreeMap<Integer, SettingsDescription<?>> versionedSetting = settingDescriptions.get(settingName);
117→            Integer highestVersion = versionedSetting.lastKey();
118→
119→            //noinspection unchecked
120→            SettingsDescription<Object> settingDesc =
121→                (SettingsDescription<Object>) versionedSetting.get(highestVersion);
122→
123→            if (settingDesc != null) {
124→                String stringValue = settingDesc.toString(internalValue);
125→
126→                serializedSettings.put(settingName, stringValue);
127→            } else {
128→                Timber.w("Settings.convert() called with a setting that should have been removed: %s", settingName);
129→            }
130→        }
131→
132→        return serializedSettings;
133→    }
134→
135→    /**
136→     * Creates a {@link TreeMap} linking version numbers to {@link SettingsDescription} instances.
137→     *
138→     * <p>
139→     * This {@code TreeMap} is used to quickly find the {@code SettingsDescription} belonging to a
140→     * content version as read by {@link SettingsImporter}. See e.g.
141→     * {@link Settings#validate(int, Map, Map, boolean)}.
142→     * </p>
143→     *
144→     * @param versionDescriptions
145→     *         A list of descriptions for a specific setting mapped to version numbers. Never
146→     *         {@code null}.
147→     *
148→     * @return A {@code TreeMap} using the version number as key, the {@code SettingsDescription}
149→     *         as value.
150→     */
151→    static TreeMap<Integer, SettingsDescription<?>> versions(V... versionDescriptions) {
152→        TreeMap<Integer, SettingsDescription<?>> map = new TreeMap<>();
153→        for (V v : versionDescriptions) {
154→            map.put(v.version, v.description);
155→        }
156→        return map;
157→    }
158→
159→
160→    static class InvalidSettingValueException extends Exception {
161→        private static final long serialVersionUID = 1L;
162→
163→        public InvalidSettingValueException() {
164→        }
165→
166→        public InvalidSettingValueException(String message) {
167→            super(message);
168→        }
169→    }
170→
171→    /**
172→     * Describes a setting.
173→     *
174→     * <p>
175→     * Instances of this class are used to convert the string representations of setting values to
176→     * an internal representation (e.g. an integer) and back.
177→     * </p><p>
178→     * Currently we use two different string representations:
179→     * </p>
180→     * <ol>
181→     *   <li>
182→     *   The one that is used by the internal preference {@link Storage}. It is usually obtained by
183→     *   calling {@code toString()} on the internal representation of the setting value (see e.g.
184→     *   {@link K9#save(StorageEditor)}).
185→     *   </li>
186→     *   <li>
187→     *   The "pretty" version that is used by the import/export settings file (e.g. colors are
188→     *   exported in #rrggbb format instead of a integer string like "-8734021").
189→     *   </li>
190→     * </ol>
191→     * <p>
192→     * <strong>Note:</strong>
193→     * For the future we should aim to get rid of the "internal" string representation. The
194→     * "pretty" version makes reading a database dump easier and the performance impact should be
195→     * negligible.
196→     * </p>
197→     */
198→    abstract static class SettingsDescription<T> {
199→        /**
200→         * The setting's default value (internal representation).
201→         */
202→        T defaultValue;
203→
204→        SettingsDescription(T defaultValue) {
205→            this.defaultValue = defaultValue;
206→        }
207→
208→        /**
209→         * Get the default value.
210→         *
211→         * @return The internal representation of the default value.
212→         */
213→        public T getDefaultValue() {
214→            return defaultValue;
215→        }
216→
217→        /**
218→         * Convert a setting's value to the string representation.
219→         *
220→         * @param value
221→         *         The internal representation of a setting's value.
222→         *
223→         * @return The string representation of {@code value}.
224→         */
225→        public String toString(T value) {
226→            return value.toString();
227→        }
228→
229→        /**
230→         * Parse the string representation of a setting's value .
231→         *
232→         * @param value
233→         *         The string representation of a setting's value.
234→         *
235→         * @return The internal representation of the setting's value.
236→         *
237→         * @throws InvalidSettingValueException
238→         *         If {@code value} contains an invalid value.
239→         */
240→        public abstract T fromString(String value) throws InvalidSettingValueException;
241→
242→        /**
243→         * Convert a setting value to the "pretty" string representation.
244→         *
245→         * @param value
246→         *         The setting's value.
247→         *
248→         * @return A pretty-printed version of the setting's value.
249→         */
250→        public String toPrettyString(T value) {
251→            return toString(value);
252→        }
253→
254→        /**
255→         * Convert the pretty-printed version of a setting's value to the internal representation.
256→         *
257→         * @param value
258→         *         The pretty-printed version of the setting's value. See
259→         *         {@link #toPrettyString(Object)}.
260→         *
261→         * @return The internal representation of the setting's value.
262→         *
263→         * @throws InvalidSettingValueException
264→         *         If {@code value} contains an invalid value.
265→         */
266→        public T fromPrettyString(String value) throws InvalidSettingValueException {
267→            return fromString(value);
268→        }
269→    }
270→
271→    static class V {
272→        public final Integer version;
273→        public final SettingsDescription<?> description;
274→
275→        V(Integer version, SettingsDescription<?> description) {
276→            this.version = version;
277→            this.description = description;
278→        }
279→    }
280→
281→    static class StringSetting extends SettingsDescription<String> {
282→        StringSetting(String defaultValue) {
283→            super(defaultValue);
284→        }
285→
286→        @Override
287→        public String fromString(String value) {
288→            return value;
289→        }
290→
291→        @Override
292→        public String toString(String value) {
293→            return value;
294→        }
295→    }
296→
297→    static class BooleanSetting extends SettingsDescription<Boolean> {
298→        BooleanSetting(boolean defaultValue) {
299→            super(defaultValue);
300→        }
301→
302→        @Override
303→        public Boolean fromString(String value) throws InvalidSettingValueException {
304→            if (Boolean.TRUE.toString().equals(value)) {
305→                return true;
306→            } else if (Boolean.FALSE.toString().equals(value)) {
307→                return false;
308→            }
309→            throw new InvalidSettingValueException();
310→        }
311→    }
312→
313→    static class ColorSetting extends SettingsDescription<Integer> {
314→        ColorSetting(int defaultValue) {
315→            super(defaultValue);
316→        }
317→
318→        @Override
319→        public Integer fromString(String value) throws InvalidSettingValueException {
320→            try {
321→                return Integer.parseInt(value);
322→            } catch (NumberFormatException e) {
323→                throw new InvalidSettingValueException();
324→            }
325→        }
326→
327→        @Override
328→        public String toPrettyString(Integer value) {
329→            int color = value & 0x00FFFFFF;
330→            return String.format("#%06x", color);
331→        }
332→
333→        @Override
334→        public Integer fromPrettyString(String value) throws InvalidSettingValueException {
335→            try {
336→                if (value.length() == 7) {
337→                    return Integer.parseInt(value.substring(1), 16) | 0xFF000000;
338→                }
339→            } catch (NumberFormatException e) { /* do nothing */ }
340→
341→            throw new InvalidSettingValueException();
342→        }
343→    }
344→
345→    static class EnumSetting<T extends Enum<T>> extends SettingsDescription<T> {
346→        private Class<T> enumClass;
347→
348→        EnumSetting(Class<T> enumClass, T defaultValue) {
349→            super(defaultValue);
350→            this.enumClass = enumClass;
351→        }
352→
353→        @Override
354→        public T fromString(String value) throws InvalidSettingValueException {
355→            try {
356→                return Enum.valueOf(enumClass, value);
357→            } catch (Exception e) {
358→                throw new InvalidSettingValueException();
359→            }
360→        }
361→    }
362→
363→    /**
364→     * A setting that has multiple valid values but doesn't use an {@link Enum} internally.
365→     *
366→     * @param <T>
367→     *         The type of the internal representation (e.g. {@code Integer}).
368→     */
369→    abstract static class PseudoEnumSetting<T> extends SettingsDescription<T> {
370→        PseudoEnumSetting(T defaultValue) {
371→            super(defaultValue);
372→        }
373→
374→        protected abstract Map<T, String> getMapping();
375→
376→        @Override
377→        public String toPrettyString(T value) {
378→            return getMapping().get(value);
379→        }
380→
381→        @Override
382→        public T fromPrettyString(String value) throws InvalidSettingValueException {
383→            for (Entry<T, String> entry : getMapping().entrySet()) {
384→                if (entry.getValue().equals(value)) {
385→                    return entry.getKey();
386→                }
387→            }
388→
389→            throw new InvalidSettingValueException();
390→        }
391→    }
392→
393→    static class FontSizeSetting extends PseudoEnumSetting<Integer> {
394→        private final Map<Integer, String> mapping;
395→
396→        FontSizeSetting(int defaultValue) {
397→            super(defaultValue);
398→
399→            Map<Integer, String> mapping = new HashMap<>();
400→            mapping.put(FontSizes.FONT_10SP, "tiniest");
401→            mapping.put(FontSizes.FONT_12SP, "tiny");
402→            mapping.put(FontSizes.SMALL, "smaller");
403→            mapping.put(FontSizes.FONT_16SP, "small");
404→            mapping.put(FontSizes.MEDIUM, "medium");
405→            mapping.put(FontSizes.FONT_20SP, "large");
406→            mapping.put(FontSizes.LARGE, "larger");
407→            this.mapping = Collections.unmodifiableMap(mapping);
408→        }
409→
410→        @Override
411→        protected Map<Integer, String> getMapping() {
412→            return mapping;
413→        }
414→
415→        @Override
416→        public Integer fromString(String value) throws InvalidSettingValueException {
417→            try {
418→                Integer fontSize = Integer.parseInt(value);
419→                if (mapping.containsKey(fontSize)) {
420→                    return fontSize;
421→                }
422→            } catch (NumberFormatException e) { /* do nothing */ }
423→
424→            throw new InvalidSettingValueException();
425→        }
426→    }
427→
428→    static class WebFontSizeSetting extends PseudoEnumSetting<Integer> {
429→        private final Map<Integer, String> mapping;
430→
431→        WebFontSizeSetting(int defaultValue) {
432→            super(defaultValue);
433→
434→            Map<Integer, String> mapping = new HashMap<>();
435→            mapping.put(1, "smallest");
436→            mapping.put(2, "smaller");
437→            mapping.put(3, "normal");
438→            mapping.put(4, "larger");
439→            mapping.put(5, "largest");
440→            this.mapping = Collections.unmodifiableMap(mapping);
441→        }
442→
443→        @Override
444→        protected Map<Integer, String> getMapping() {
445→            return mapping;
446→        }
447→
448→        @Override
449→        public Integer fromString(String value) throws InvalidSettingValueException {
450→            try {
451→                Integer fontSize = Integer.parseInt(value);
452→                if (mapping.containsKey(fontSize)) {
453→                    return fontSize;
454→                }
455→            } catch (NumberFormatException e) { /* do nothing */ }
456→
457→            throw new InvalidSettingValueException();
458→        }
459→    }
460→
461→    static class IntegerRangeSetting extends SettingsDescription<Integer> {
462→        private int start;
463→        private int end;
464→
465→        IntegerRangeSetting(int start, int end, int defaultValue) {
466→            super(defaultValue);
467→            this.start = start;
468→            this.end = end;
469→        }
470→
471→        @Override
472→        public Integer fromString(String value) throws InvalidSettingValueException {
473→            try {
474→                int intValue = Integer.parseInt(value);
475→                if (start <= intValue && intValue <= end) {
476→                    return intValue;
477→                }
478→            } catch (NumberFormatException e) { /* do nothing */ }
479→
480→            throw new InvalidSettingValueException();
481→        }
482→    }
483→}
